const PLUGIN_URI: &str = "http://faust-lv2.googlecode.com/Prefreak";
const PLUGIN_DIR: &str = "Prefreak";

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "Prefreak.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "Prefreak.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "Prefreak.dll";

// Port indices (from TTL)
const PORT_CTRL_BLUR: usize = 0;
const PORT_CTRL_LEVEL: usize = 1;
const PORT_AUDIO_IN_IN0: usize = 2;
const PORT_AUDIO_IN_IN1: usize = 3;
const PORT_AUDIO_OUT_OUT0: usize = 4;
const PORT_AUDIO_OUT_OUT1: usize = 5;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_REVERB.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            float_parameter("blur", "Blur", None, Some(1.64), 0.001, 15.0, 0.1, ParameterUnit::None),
            float_parameter("level", "Level", None, Some(0.26), 0.0, 1.5, 0.01, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let blur = required_f32(params, "blur").map_err(anyhow::Error::msg)?;
    let level = required_f32(params, "level").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BLUR, blur),
        (PORT_CTRL_LEVEL, level),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN0, PORT_AUDIO_IN_IN1], &[PORT_AUDIO_OUT_OUT0, PORT_AUDIO_OUT_OUT1], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

